def is_leap_year(year):
    """
    Returns True if a year is a leap year, False otherwise.
    """
    # Check if year is divisible by 4
    if year % 4 == 0:
        # Check if year is divisible by 100 but not by 400
        if year % 100 != 0 or year % 400 == 0:
            # If both conditions are met, the year is a leap year
            return True
        else:
            # If only one condition is met, the year is not a leap year
            return False
    else:
        # If year is not divisible by 4, it is not a leap year
        return False

def find_missing_number(lst):
    # Create a dictionary to store the count of each integer in the list
    num_counts = {}

    # Iterate over the list and increment the count for each integer
    for num in lst:
        if num not in num_counts:
            num_counts[num] = 1
        else:
            num_counts[num] += 1

    # Initialize the missing number variable
    missing_num = None

    # Iterate over the dictionary keys (integers)
    for num, count in num_counts.items():

        # If the count is less than 2, it means there is a missing number
        if count < 2:

            # Check if the current number is greater than the missing number
            if lst.index(missing_num) + 1 == len(lst):
                missing_num = lst[-1]

            # Otherwise, add the current number to the list of missing numbers
            lst.append(missing_num)

    # Return the missing number
    return missing_num

def pascals_triangle(n):
    if n < 0:
        return "Error: Invalid input. Please provide a non-negative integer."

    triangle = []
    for i in range(1, n+1):
        row = [1]

        for j in range(1, i):
            row.append(triangle[j-1][i-j])

        triangle.append(row)

    return triangle

def is_monotonic(lst):
    # Check if the list is empty
    if len(lst) == 0:
        return True

    # Iterate through each element in the list
    for i in range(len(lst)):
        # Check if the current element is less than the previous element
        if lst[i] < lst[i-1]:
            return False

        # If the current element is greater than the previous element, move to the next element
        elif lst[i] > lst[i-1]:
            return True

    # If we reach the end of the list without finding any decreasing or increasing sequence,
    # the list is monotone increasing or monotone decreasing
    return True
